export function Marquee() {
  return (
    <div className="relative overflow-hidden border-y border-card-border bg-card-bg/50 py-5">
      {/* Fade edges */}
      <div className="pointer-events-none absolute inset-y-0 left-0 z-10 w-32 bg-gradient-to-r from-background to-transparent" />
      <div className="pointer-events-none absolute inset-y-0 right-0 z-10 w-32 bg-gradient-to-l from-background to-transparent" />

      <div className="group flex">
        {[0, 1].map((copy) => (
          <div
            key={copy}
            className="flex shrink-0 animate-marquee items-center gap-12 pr-12 group-hover:[animation-play-state:paused]"
            aria-hidden={copy === 1}
          >
            {techStack.map((tech) => (
              <span
                key={`${copy}-${tech.name}`}
                className="flex items-center gap-2.5 whitespace-nowrap text-sm text-muted/60 transition-colors hover:text-heading"
              >
                <span className="opacity-60">{tech.svg}</span>
                {tech.name}
              </span>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}
